void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b)
{
    /* clang-format off */
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        const double* row = L[i].data();
        /* inner loop: xt[i] -= L[i][j] * x[j]  */
        for (int j = 0; j < i; ++j) {
            sum -= row[j] * x[j];
