inline int min_int(int a, int b) { return a < b ? a : b; }

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Parallelise the outer `i` loop for each `k`.  The inner `j` loop is kept
    // as a normal loop to maximise cache reuse.  The inline `min_int()` saves
    // a function call overhead compared to std::min.
#pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        for (int i = 0; i < n; ++i) {
            int* row_i = path[i].data();
            int  dik   = row_i[k];
            for (int j = 0; j < n; ++j) {
                int new_dist = dik + path[k][j];
                row_i[j] = min_int(row_i[j], new_dist);
            }
        }
    }
}
