// Optimised LU factorisation kernel for GCC O2 + OpenMP
#include <vector>
#include <cstddef>
#include <omp.h>

/* Helper to treat a 2‑D std::vector as a 1‑D contiguous buffer */
static inline double* row_ptr(std::vector<std::vector<double>>& A, std::size_t i)
{
    return A[i].data();                      // C++11 guarantees contiguous storage
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(std::size_t n,
               std::vector<std::vector<double>>& A)
{
    /* Parallelise the outer loop (each iteration is independent
       once the required elements of the current row are finished).
       Use static scheduling to keep the overhead low on 8 cores. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        double* Ai = row_ptr(A, i);

        /* --- Compute below‑diagonal entries (i, j < i) --- */
        for (std::size_t j = 0; j < i; ++j) {
            double* Aj      = row_ptr(A, j);
            double* Aij_inv = Ai + j;          // A[i][j] as pointer

            /* Inner k‑loop for dot‑product */
            for (std::size_t k = 0; k < j; ++k) {
                *Aij_inv -= Ai[k] * Aju[k];
            }
            *Aij_inv /= Aj[j];                  // Divide by pivot
        }

        /* --- Compute upper‑triangular part (i, j >= i) --- */
        for (std::size_t j = i; j < n; ++j) {
            double* Aj  = row_ptr(A, j);
            double* Aij = Ai + j;

            for (std::size_t k = 0; k < i; ++k) {
                *Aij -= Ai[k] * Aj[k];
            }
        }
    }
}
