/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    // Avoid repeated look‑up of the loop bounds
    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t firstIdx = 1;
    const std::size_t lastIdx  = N - 2;               // inclusive
    const double inv3 = 1.0 / 3.0;

    // Use raw pointers for a small speed win
    double* a = A.data();
    double* b = B.data();

    // Parallelise the two inner loops with `omp parallel for`.
    // The two loops are independent; they can be executed
    // concurrently if we introduce a barrier between them.
    for (int t = 0; t < tsteps; ++t) {
        /* ---- first update (A → B) ---- */
        #pragma omp parallel for schedule(static)
        for (std::size_t i = firstIdx; i <= lastIdx; ++i) {
            /* Structure‑of‑arrays layout gives us a small
             * cache‑friendly pattern: we just read three
             * consecutive elements and write one. */
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* ---- second update (B → A) ---- */
        #pragma omp parallel for schedule(static)
        for (std::size_t i = firstIdx; i <= lastIdx; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
