#include <algorithm>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {
    // Convert the 2‑D std::vector matrices to contiguous raw pointers
    // (they are already contiguous row‑major, but we use raw pointers
    //  to avoid bounds checks and enhance cache locality).
    double *A_buf = &A[0][0];
    double *B_buf = &B[0][0];
    double *C_buf = &C[0][0];

    const std::size_t A_stride = nk;   // columns in A
    const std::size_t B_stride = nj;   // columns in B
    const std::size_t C_stride = nj;   // columns in C

    // Parallelise over the outermost dimension (rows of C).
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *C_row = C_buf + i * C_stride;
        // Scale current row of C by beta
        for (int j = 0; j < nj; ++j) {
            C_row[j] *= beta;
        }

        const double *A_row = A_buf + i * A_stride;
        for (int k = 0; k < nk; ++k) {
            const double a_val = A_row[k] * alpha;
            const double *B_row = B_buf + k * B_stride;
            double *C_elem = C_row;
            for (int j = 0; j < nj; ++j) {
                *C_elem += a_val * B_row[j];
                ++C_elem;
            }
        }
    }
}
