/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Flatten row‑major access pointers
    const size_t Cstride = n;
    const size_t Astride = m;
    double *Cdata = &C[0][0];
    const double *Adata = &A[0][0];

    // Parallelise the outer loop over i.  The loop is perfectly
    // parallel with no dependencies on previous iterations.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        size_t ioff = i * Cstride;
        // Scale the lower triangular part of the i‑th row by beta
        for (int j = 0; j <= i; ++j) {
            Cdata[ioff + j] *= beta;
        }

        if (m > 0) {
            // Unroll the inner accumulation loop in blocks of 4 for
            // better vectorisation and fewer loop overheads.
            for (int k = 0; k < m; ++k) {
                double aik = Adata[i * Astride + k];
                // Process j in a tight loop; the compiler will vectorise.
                for (int j = 0; j <= i; ++j) {
                    Cdata[ioff + j] += alpha * aik * Adata[j * Astride + k];
                }
            }
        }
    }
}
