/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    // Flatten the 2‑D read‑only matrix for better cache utilisation
    std::vector<double> A_flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), A_flat.begin() + i * n);

    const double *Aptr = A_flat.data();

    /* Use OpenMP to parallelise the outer loops.
       The inner loop is manually unrolled by a factor of four
       for a small reduction in overhead.                          */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *xi1 = &x1[i];
        const double *row = Aptr + i * n;
        const double *y1 = y_1.data();

        // First matrix–vector product
        double sum1 = 0.0;
        int j = 0;
        for (; j <= n - 4; j += 4) {
            sum1 += row[j]     * y1[j];
            sum1 += row[j + 1] * y1[j + 1];
            sum1 += row[j + 2] * y1[j + 2];
            sum1 += row[j + 3] * y1[j + 3];
        }
        for (; j < n; ++j)
            sum1 += row[j] * y1[j];
        *xi1 += sum1;

        // Second matrix–vector product (using the transpose)
        double *xi2 = &x2[i];
        const double *y2 = y_2.data();
        double sum2 = 0.0;
        for (int k = 0; k < n; ++k)
            sum2 += Aptr[k * n + i] * y2[k];
        *xi2 += sum2;
    }
}
