    for (int i = 0; i < n; ++i) q[i] = 0.0;

    /* Main kernel:
       s[j] += r[i] * A[i][j];
       q[i] += A[i][j] + p[j];
    */
#pragma omp parallel for schedule(static) reduction(+:s[:m])
    for (int i = 0; i < n; ++i) {
        const std::vector<double>& Ai = A[i];
        double ri = r[i];
        for (int j = 0; j < m; ++j) {
            s[j] += ri * Ai[j];
            q[i] += Ai[j] + p[j];
        }
    }
