/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    /* For each column k */
    for (int k = 0; k < n; ++k) {
        /* Compute the 2‑norm of column k of A (parallel reduction). */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm += val * val;
        }
        R[k][k] = std::sqrt(nrm);

        /* Q = A / ||A||. */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* Orthogonalise remaining columns. */
        for (int j = k + 1; j < n; ++j) {
            /* Compute R[k][j] = Q_k^T * A_j. */
            double rij = 0.0;
#pragma omp parallel for reduction(+:rij) schedule(static)
            for (int i = 0; i < m; ++i) {
                rij += Q[i][k] * A[i][j];
            }
            R[k][j] = rij;

            /* Update A_j = A_j - Q_k * R[k][j]. */
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rij;
            }
        }
    }
}
