/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
		   std::vector<std::vector<double>>& A,
		   std::vector<double>& b,
		   std::vector<double>& x,
		   std::vector<double>& y) {
    /*-- LU decomposition ----------------------------------------------------*/
    for (int i = 0; i < n; ++i) {
        double* row_i = A[i].data();          /* pointer to i‑th row          */
        /* First part – U */
        for (int j = 0; j < i; ++j) {
            double w = row_i[j];
            const double* row_k = A[j].data();
            for (int k = 0; k < j; ++k)
                w -= row_i[k] * row_k[j];
            row_i[j] = w / row_k[j];          /* L[i][j] = w / U[j][j]       */
        }
        /* Second part – U remaining columns */
        for (int j = i; j < n; ++j) {
            double w = row_i[j];
            for (int k = 0; k < i; ++k)
                w -= row_i[k] * A[k][j];
            row_i[j] = w;
        }
    }

    /*-- Forward substitution -----------------------------------------------*/
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        const double* row_i = A[i].data();
        for (int j = 0; j < i; ++j)
            w -= row_i[j] * y[j];
        y[i] = w;
    }

    /*-- Backward substitution ----------------------------------------------*/
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        const double* row_i = A[i].data();
        for (int j = i + 1; j < n; ++j)
            w -= row_i[j] * x[j];
        x[i] = w / row_i[i];
    }
}
