    double *a = &A[0][0];

    /* 1)   A += u1⊗v1 + u2⊗v2  */
#pragma omp parallel for collapse(2) schedule(static, 64)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        double *ai = a + i * n;            /* row i */
        for (int j = 0; j < n; ++j) {
            ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2)   x += beta * Aᵀ * y  */
#pragma omp parallel for schedule(static, 64)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += a[j * n + i] * y[j];
        }
        x[i] = xi + beta * sum;
    }

    /* 3)   x += z  */
#pragma omp parallel for schedule(static, 64)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4)   w += alpha * A * x  */
