    for (int i = 0; i < n; ++i) {
        double wi   = w[i];
        double *ai  = a + i * n;           /* row i */
        double tmp  = 0.0;
        for (int j = 0; j < n; ++j) {
            tmp += ai[j] * x[j];
        }
        w[i] = wi + alpha * tmp;
    }
