#include <omp.h>

/* Optimized version of the Nussinov kernel */
static inline int match(int b1, int b2) noexcept {
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    // Pointers to the rows of the table for faster access
    std::vector<int*> tbl_rows(n);
    for (int i = 0; i < n; ++i) {
        tbl_rows[i] = table[i].data();
    }

    // The outer loop runs over i from n-1 down to 0.
    // It can be safely parallelised because each i only reads
    // rows with indices > i and writes to row i.
    #pragma omp parallel for schedule(dynamic, 16)  // balance load on 8 cores
    for (int i = n - 1; i >= 0; --i) {
        int* row_i = tbl_rows[i];
        const int* row_ip1 = (i + 1 < n) ? tbl_rows[i + 1] : nullptr;

        for (int j = i + 1; j < n; ++j) {
            int best = row_i[j];

            // table[i][j-1]
            if (j - 1 >= 0) {
                best = std::max(best, row_i[j - 1]);
            }

            // table[i+1][j]
            if (row_ip1) {
                best = std::max(best, row_ip1[j]);
            }

            // table[i+1][j-1] + match
            if (row_ip1 && j - 1 >= 0) {
                if (i < j - 1) {
                    best = std::max(best, row_ip1[j - 1] + match(seq[i], seq[j]));
                } else {
                    best = std::max(best, row_ip1[j - 1]);
                }
            }

            // max over splits k
            for (int k = i + 1; k < j; ++k) {
                int val = row_i[k] + tbl_rows[k + 1][j];
                if (val > best) best = val;
            }

            row_i[j] = best;
        }
    }
}
