void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps   = 0.1;
    const double inv_n = 1.0 / static_cast<double>(n);
    const double sqrt_n = std::sqrt(static_cast<double>(n));

    /* ------------------------------------------------------------------
       1. Compute per‑column sums and squared sums in a single pass
       ------------------------------------------------------------------ */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double s  = 0.0;
        double ss = 0.0;
        for (int i = 0; i < n; ++i) {
            double v = data[i][j];
            s  += v;
            ss += v * v;
        }
        mean[j]  = s * inv_n;
        double var = ss * inv_n - mean[j] * mean[j];
        var = var < 0.0 ? 0.0 : var;   // guard against rounding
        stddev[j] = std::sqrt(var);
        if (stddev[j] <= eps) stddev[j] = 1.0;   // avoid division by 0
    }

    /* ------------------------------------------------------------------
       2. Normalize the data matrix
       ------------------------------------------------------------------ */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_n / stddev[j];
        }
    }

    /* ------------------------------------------------------------------
       3. Compute the symmetric correlation matrix
          corr[i][j] = sum_k data[k][i] * data[k][j]
       ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;      // reflect symmetry
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
