/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    // Parallelise across rows; each row can be processed independently
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Upper triangular part (i > j)
        for (int j = 0; j < i; ++j) {
            double sum = A[i][j];
            // compute dot product of row i and row j up to column j-1
            for (int k = 0; k < j; ++k) {
                sum -= A[i][k] * A[j][k];
            }
            A[i][j] = sum / A[j][j];
        }

        // Diagonal element
        double sum = A[i][i];
        for (int k = 0; k < i; ++k) {
            sum -= A[i][k] * A[i][k];
        }
        A[i][i] = std::sqrt(sum);
    }
