/*----------------------------------------------------------------------------
 *  Compute the column‑wise mean, center the data, and form the covariance
 *  matrix.  The input  and output matrices are still std::vector<nested>
 *  because the harness expects that layout.  To achieve high performance
 *  we (a) convert to a flat 1‑D buffer for the inner loops, and
 *  (b) parallelise all independent loops with OpenMP.
 *-----------------------------------------------------------------------------*/
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* --------------------------------------------------------------------
     *  Prepare a flat view of the data (row major).
     *  The temporary buffer is necessary only for vectorised inner loops;
     *  we keep the original layout unchanged for the caller.
     *  -------------------------------------------------------------------- */
    std::vector<double> flat(n * m);            // temporary buffer
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {              // copy to flat
        for (int j = 0; j < m; ++j) {
            flat[i * m + j] = data[i][j];
        }
    }

    /* --------------------------------------------------------------------
     *  1. Compute column means – each thread handles a subset of columns
     * -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += flat[i * m + j];
        mean[j] = sum / n;
    }

    /* --------------------------------------------------------------------
     *  2. Center the data (subtract the mean from each column)
     * -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            flat[i * m + j] -= mean[j];
        }
    }

    /* --------------------------------------------------------------------
     *  3. Compute the covariance matrix.
     *  cov[i][j] = (Σ_k x_ki * x_kj) / (n-1)
     *  We use only the upper triangle and mirror it.
     * -------------------------------------------------------------------- */
    const double denom = 1.0 / (n - 1.0);
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += flat[k * m + i] * flat[k * m + j];
            }
            cov[i][j] = sum * denom;
            cov[j][i] = cov[i][j];          // exploit symmetry
        }
