    std::vector<double> a(ni * nk), b(nk * nj);
    std::vector<double> c(nj * nm), d(nm * nl);
    for (int i = 0; i < ni; ++i)
        for (int k = 0; k < nk; ++k)
            a[i * nk + k] = A[i][k];
    for (int k = 0; k < nk; ++k)
        for (int j = 0; j < nj; ++j)
            b[k * nj + j] = B[k][j];
    for (int i = 0; i < nj; ++i)
        for (int k = 0; k < nm; ++k)
