            e[i * nj + j] = sum;
        }

    /* 2nd GEMM: F = C * D  (nj x nl) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < nj; ++i)
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k)
                sum += c[i * nm + k] * d[k * nl + j];
            f[i * nl + j] = sum;
        }

    /* 3rd GEMM: G = E * F  (ni x nl) */
    #pragma omp parallel for collapse(2) schedule(static)
