/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(
    int tsteps,
    int n,
    std::vector<std::vector<double>>& A,
    std::vector<std::vector<double>>& B)
{
    const std::size_t stride = static_cast<std::size_t>(n);
    const double coef = 0.2;

    /* Flatten the 2‑D std::vector into a raw pointer for fast indexed access.
       The input buffers are guaranteed to be rectangular. */
    double* pA = &A[0][0];
    double* pB = &B[0][0];

    /* Main time‑stepping loop.  The two sweeps are split and each
       is parallelised over the inner spatial dimension (rows).   */
    for (int t = 0; t < tsteps; ++t) {
        /*---------- Sweep 1: compute B from A ----------*/
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            const std::size_t base = static_cast<std::size_t>(i) * stride;
            const std::size_t front = static_cast<std::size_t>(i - 1) * stride;
            const std::size_t back  = static_cast<std::size_t>(i + 1) * stride;

            for (int j = 1; j < n - 1; ++j) {
                const std::size_t idx = base + j;
                pB[idx] = coef * (
                    pA[idx]                     // centre
                  + pA[idx - 1]                 // left
                  + pA[idx + 1]                 // right
                  + pA[back + j]                // south
                  + pA[front + j]);             // north
            }
        }

        /*---------- Sweep 2: compute A from B ----------*/
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            const std::size_t base = static_cast<std::size_t>(i) * stride;
            const std::size_t front = static_cast<std::size_t>(i - 1) * stride;
            const std::size_t back  = static_cast<std::size_t>(i + 1) * stride;

            for (int j = 1; j < n - 1; ++j) {
                const std::size_t idx = base + j;
                pA[idx] = coef * (
                    pB[idx]                     // centre
                  + pB[idx - 1]                 // left
                  + pB[idx + 1]                 // right
                  + pB[back + j]                // south
                  + pB[front + j]);             // north
            }
        }
    }
}
