// ---------------------------------------------------------------
// Optimised Deriche filter kernel
// ---------------------------------------------------------------
#include <cmath>
#include <vector>
#include <omp.h>

/* Original function signature – must stay unchanged */
void kernel_deriche(int w, int h, double alpha,
        std::vector<std::vector<float>>& imgIn,
        std::vector<std::vector<float>>& imgOut,
        std::vector<std::vector<float>>& y1,
        std::vector<std::vector<float>>& y2)
{
    /* ----- pre‑compute constants ----------------------------------- */
    const float alpha_f = static_cast<float>(alpha);
    const float exp_a = std::exp(-alpha_f);
    const float exp_2a = exp_a * exp_a;
    const float denom = 1.0f + 2.0f * alpha_f * exp_a - exp_2a;
    const float k = 1.0f - exp_a * (1.0f - exp_a) / denom;

    const float a1 = k, a2 = k * exp_a * (alpha_f - 1.0f), a3 = k * exp_a * (alpha_f + 1.0f), a4 = -k * exp_2a;
    const float a5 = k, a6 = k * exp_a * (alpha_f - 1.0f), a7 = k * exp_a * (alpha_f + 1.0f), a8 = -k * exp_2a;
    const float b1 = std::pow(2.0f, -alpha_f), b2 = -exp_2a;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ----- Row‑wise accumulation (forward) ------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        float* const inRow  = &imgIn[i][0];
        float* const outRow = &y1[i][0];
        for (int j = 0; j < h; ++j) {
            const float val = inRow[j];
            const float res = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            outRow[j] = res;
            xm1 = val;
            ym2 = ym1;
            ym1 = res;
        }
    }

    /* ----- Row‑wise accumulation (backward) ---------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        float* const inRow  = &imgIn[i][0];
        float* const outRow = &y2[i][0];
        for (int j = h - 1; j >= 0; --j) {
            const float val = inRow[j];
            const float res = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            outRow[j] = res;
            xp2 = xp1;
            xp1 = val;
            yp2 = yp1;
            yp1 = res;
        }
    }

    /* ----- Combine forward and backward results ------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float* const outRow = &imgOut[i][0];
        const float* const r1 = &y1[i][0];
        const float* const r2 = &y2[i][0];
        for (int j = 0; j < h; ++j) {
            outRow[j] = c1 * (r1[j] + r2[j]);
        }
    }

    /* ----- Column‑wise accumulation (forward) --------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float val = imgOut[i][j];
            const float res = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = res;
            tm1 = val;
            ym2 = ym1;
            ym1 = res;
        }
    }

    /* ----- Column‑wise accumulation (backward) -------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float val = imgOut[i][j];
            const float res = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = res;
            tp2 = tp1;
            tp1 = val;
            yp2 = yp1;
            yp1 = res;
        }
    }

    /* ----- Final combination -------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float* const outRow = &imgOut[i][0];
        const float* const r1 = &y1[i][0];
        const float* const r2 = &y2[i][0];
        for (int j = 0; j < h; ++j) {
            outRow[j] = c2 * (r1[j] + r2[j]);
        }
    }
}
